/* ═══════════════════════════════════════════════════════════════════════════
   MultiChartPage — TradingView-inspired multi-panel chart workspace
   Layout presets: 1x1, 1x2, 2x1, 2x2, 1x3, 3x1
   Features:
     - Independent charts per cell (symbol, timeframe, OHLCV)
     - Synchronized crosshair across panels
     - Save/load layouts to localStorage
     - Fullscreen toggle per cell
     - Responsive (mobile stacks vertically)
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import ChartCell from '../components/ChartCell';
import usePageTitle from '../hooks/usePageTitle';
import useWatchlists from '../hooks/useWatchlists';
import { api } from '../utils/api';
import s from './MultiChartPage.module.css';

const STORAGE_KEY = 'aura_multichart_layout';

/* ── Layout definitions ────────────────────────────────────────── */
const LAYOUTS = [
  { id: '1x1', label: '1 Chart',   cols: 1, rows: 1, count: 1 },
  { id: '1x2', label: '1x2',       cols: 1, rows: 2, count: 2 },
  { id: '2x1', label: '2x1',       cols: 2, rows: 1, count: 2 },
  { id: '2x2', label: '2x2',       cols: 2, rows: 2, count: 4 },
  { id: '1x3', label: '1x3',       cols: 1, rows: 3, count: 3 },
  { id: '3x1', label: '3x1',       cols: 3, rows: 1, count: 3 },
];

const DEFAULT_SYMBOLS = ['SPY', 'AAPL', 'MSFT', 'TSLA', 'NVDA', 'AMD', 'QQQ', 'GOOGL', 'AMZN'];

/* ── Layout icon SVG ───────────────────────────────────────────── */
function LayoutIcon({ cols, rows, active }) {
  const size = 22;
  const pad = 2;
  const gap = 1.5;
  const cellW = (size - pad * 2 - gap * (cols - 1)) / cols;
  const cellH = (size - pad * 2 - gap * (rows - 1)) / rows;
  const rects = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      rects.push(
        <rect
          key={`${r}-${c}`}
          x={pad + c * (cellW + gap)}
          y={pad + r * (cellH + gap)}
          width={cellW}
          height={cellH}
          rx={1.2}
          fill={active ? 'var(--color-blue, #60A5FA)' : 'var(--color-text-secondary, #90A3AF)'}
          opacity={active ? 1 : 0.4}
        />
      );
    }
  }
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {rects}
    </svg>
  );
}

/* ── Load saved state from localStorage ────────────────────────── */
function loadSavedState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw);
      if (parsed && parsed.layoutId && parsed.cells) {
        return parsed;
      }
    }
  } catch (_) { /* corrupt data, ignore */ }
  return null;
}

function saveState(layoutId, cells, syncEnabled) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ layoutId, cells, syncEnabled }));
  } catch (_) { /* storage full, ignore */ }
}

/* ═══════════════════════════════════════════════════════════════════════════
   MultiChartPage Component
   ═══════════════════════════════════════════════════════════════════════════ */
export default function MultiChartPage() {
  usePageTitle('Multi-Chart');

  const saved = useRef(loadSavedState()).current;
  const { watchlists } = useWatchlists();

  const [layoutId, setLayoutId] = useState(saved?.layoutId || '2x2');
  const [syncEnabled, setSyncEnabled] = useState(saved?.syncEnabled ?? true);
  const [syncSource, setSyncSource] = useState(null);
  const [syncTime, setSyncTime] = useState(null);
  const [fullscreenCell, setFullscreenCell] = useState(null);
  const [watchlistOpen, setWatchlistOpen] = useState(false);
  const [liveSignalCount, setLiveSignalCount] = useState(0);
  const [isMobile, setIsMobile] = useState(
    typeof window !== 'undefined' ? window.innerWidth < 768 : false
  );

  // Cell configurations: { [cellId]: { symbol, timeframe, smaEnabled } }
  const [cellConfigs, setCellConfigs] = useState(() => {
    if (saved?.cells) return saved.cells;
    const configs = {};
    for (let i = 0; i < 9; i++) {
      configs[i] = {
        symbol: DEFAULT_SYMBOLS[i] || DEFAULT_SYMBOLS[i % DEFAULT_SYMBOLS.length],
        timeframe: '1D',
        smaEnabled: false,
      };
    }
    return configs;
  });

  const layout = LAYOUTS.find((l) => l.id === layoutId) || LAYOUTS[3];

  /* ── Responsive ──────────────────────────────────────────────── */
  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  /* ── Poll live signal count ────────────────────────────────── */
  useEffect(() => {
    let cancelled = false;
    async function fetchLiveSignals() {
      try {
        const data = await api('/scanners/signals/live', { silent: true });
        if (!cancelled) {
          const sigs = data?.signals || data?.results || data || [];
          setLiveSignalCount(Array.isArray(sigs) ? sigs.length : 0);
        }
      } catch { /* ignore */ }
    }
    fetchLiveSignals();
    const interval = setInterval(fetchLiveSignals, 60000); // refresh every 60s
    return () => { cancelled = true; clearInterval(interval); };
  }, []);

  /* ── Apply watchlist symbol to a cell ──────────────────────── */
  const handleWatchlistSymbolSelect = useCallback((sym) => {
    // Apply the selected symbol to the first visible cell (or focused cell)
    const firstCellId = fullscreenCell !== null ? fullscreenCell : 0;
    setCellConfigs((prev) => ({
      ...prev,
      [firstCellId]: { ...prev[firstCellId], symbol: sym },
    }));
    setWatchlistOpen(false);
  }, [fullscreenCell]);

  /* ── Persist state ───────────────────────────────────────────── */
  useEffect(() => {
    saveState(layoutId, cellConfigs, syncEnabled);
  }, [layoutId, cellConfigs, syncEnabled]);

  /* ── Crosshair sync handler ──────────────────────────────────── */
  const handleCrosshairMove = useCallback((cellId, time) => {
    if (!syncEnabled) return;
    setSyncSource(cellId);
    setSyncTime(time);
  }, [syncEnabled]);

  /* ── Fullscreen toggle ───────────────────────────────────────── */
  const handleFullscreenToggle = useCallback((cellId) => {
    setFullscreenCell((prev) => prev === cellId ? null : cellId);
  }, []);

  /* ── Cell config change handler ──────────────────────────────── */
  const handleConfigChange = useCallback((cellId, config) => {
    setCellConfigs((prev) => ({
      ...prev,
      [cellId]: config,
    }));
  }, []);

  /* ── Layout change ───────────────────────────────────────────── */
  const handleLayoutChange = (id) => {
    setLayoutId(id);
    setFullscreenCell(null);
  };

  /* ── Compute grid style ──────────────────────────────────────── */
  const isFs = fullscreenCell !== null;
  const effectiveCols = isMobile ? 1 : (isFs ? 1 : layout.cols);
  const effectiveRows = isMobile ? layout.count : (isFs ? 1 : layout.rows);

  const gridStyle = {
    gridTemplateColumns: `repeat(${effectiveCols}, 1fr)`,
    gridTemplateRows: isFs ? '1fr' : `repeat(${effectiveRows}, 1fr)`,
    gap: isMobile ? '8px' : '4px',
    padding: isMobile ? '8px' : '4px',
  };

  /* ── Cells to render ─────────────────────────────────────────── */
  const cellCount = layout.count;
  const cellsToRender = isFs
    ? [fullscreenCell]
    : Array.from({ length: cellCount }, (_, i) => i);

  return (
    <div className={s.pageRoot}>
      {/* ── Top toolbar ────────────────────────────────────────── */}
      <div className={`${s.toolbar} ${isMobile ? s.toolbarMobile : ''}`}>
        {/* Title */}
        <h1 className={`${s.title} ${isMobile ? s.titleMobile : ''}`}>
          Multi-Chart
        </h1>

        {/* Divider */}
        <div className={s.divider} />

        {/* Layout preset buttons */}
        <div className={s.layoutPresets}>
          <span className={s.layoutLabel}>Layout</span>
          {LAYOUTS.map((l) => (
            <button
              key={l.id}
              onClick={() => handleLayoutChange(l.id)}
              title={l.label}
              className={`${s.layoutBtn} ${layoutId === l.id ? s.layoutBtnActive : ''}`}
            >
              <LayoutIcon cols={l.cols} rows={l.rows} active={layoutId === l.id} />
            </button>
          ))}
        </div>

        <div className={s.spacer} />

        {/* Sync crosshair toggle */}
        <button
          onClick={() => setSyncEnabled((v) => !v)}
          title={syncEnabled ? 'Crosshair sync ON' : 'Crosshair sync OFF'}
          className={`${s.toolbarBtn} ${syncEnabled ? s.syncBtnActive : ''}`}
        >
          <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path d="M8 2v12M2 8h12" />
            <circle cx="8" cy="8" r="2" />
          </svg>
          Sync
        </button>

        {/* Watchlist toggle */}
        {!isMobile && (
          <button
            onClick={() => setWatchlistOpen((v) => !v)}
            title="Toggle watchlist panel"
            className={`${s.toolbarBtn} ${watchlistOpen ? s.syncBtnActive : ''}`}
          >
            <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.3">
              <path d="M8 1.5l1.76 3.56 3.93.57-2.84 2.77.67 3.9L8 10.42l-3.52 1.88.67-3.9L2.31 5.63l3.93-.57z" />
            </svg>
            Watchlist
          </button>
        )}

        {/* Live signal indicator */}
        {liveSignalCount > 0 && (
          <span className={s.statusSync} style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 11 }}>
            <svg width="8" height="8" viewBox="0 0 10 10">
              <polygon points="5,0 10,10 0,10" fill="var(--color-green, #3FB950)" />
            </svg>
            {liveSignalCount} live signal{liveSignalCount !== 1 ? 's' : ''}
          </span>
        )}

        {/* Reset layout */}
        <button
          onClick={() => {
            const configs = {};
            for (let i = 0; i < 9; i++) {
              configs[i] = {
                symbol: DEFAULT_SYMBOLS[i] || DEFAULT_SYMBOLS[i % DEFAULT_SYMBOLS.length],
                timeframe: '1D',
                smaEnabled: false,
              };
            }
            setCellConfigs(configs);
            setLayoutId('2x2');
            setFullscreenCell(null);
            setSyncEnabled(true);
          }}
          title="Reset to defaults"
          className={s.toolbarBtn}
        >
          <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path d="M2 8a6 6 0 1 1 1.76 4.24" />
            <path d="M2 12V8h4" />
          </svg>
          Reset
        </button>
      </div>

      {/* ── Watchlist sidebar ──────────────────────────────────── */}
      {watchlistOpen && !isMobile && (
        <div style={{
          position: 'fixed', top: 56, right: 0, bottom: 28, width: 200, zIndex: 50,
          background: 'var(--color-surface, #161B22)',
          borderLeft: '1px solid var(--color-border, #30363D)',
          overflowY: 'auto',
          display: 'flex', flexDirection: 'column',
        }}>
          <div style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            padding: '8px 10px', borderBottom: '1px solid var(--color-border, #30363D)',
          }}>
            <span style={{ fontSize: 12, fontWeight: 700, color: 'var(--color-text, #E6EDF3)' }}>
              Watchlist
            </span>
            <button
              onClick={() => setWatchlistOpen(false)}
              style={{ background: 'none', border: 'none', color: 'var(--color-text-secondary, #8B949E)', cursor: 'pointer', fontSize: 14 }}
            >
              x
            </button>
          </div>
          {watchlists.length === 0 && (
            <div style={{ padding: '16px 10px', color: 'var(--color-text-secondary, #8B949E)', fontSize: 11 }}>
              No watchlists found. Create one on the Watchlists page.
            </div>
          )}
          {watchlists.map((wl) => (
            <div key={wl.id}>
              <div style={{
                padding: '6px 10px', fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                color: 'var(--color-text-secondary, #8B949E)',
                borderBottom: '1px solid var(--color-border, #30363D)',
                letterSpacing: 0.5,
              }}>
                {wl.name}
              </div>
              {(wl.symbols || []).map((sym) => {
                const symStr = typeof sym === 'string' ? sym : sym.symbol;
                return (
                  <button
                    key={symStr}
                    onClick={() => handleWatchlistSymbolSelect(symStr)}
                    style={{
                      display: 'block', width: '100%', textAlign: 'left',
                      padding: '5px 10px', border: 'none', cursor: 'pointer',
                      background: 'transparent', color: 'var(--color-text, #E6EDF3)',
                      fontFamily: "'JetBrains Mono', monospace", fontSize: 11, fontWeight: 600,
                      borderBottom: '1px solid var(--color-border, #30363D)',
                    }}
                    onMouseEnter={(e) => { e.target.style.background = 'var(--color-surface-hover, #1C2128)'; }}
                    onMouseLeave={(e) => { e.target.style.background = 'transparent'; }}
                  >
                    {symStr}
                  </button>
                );
              })}
            </div>
          ))}
        </div>
      )}

      {/* ── Chart grid ─────────────────────────────────────────── */}
      <div className={s.chartGrid} style={{
        ...gridStyle,
        ...(watchlistOpen && !isMobile ? { marginRight: 200 } : {}),
      }}>
        {cellsToRender.map((cellId) => {
          const cfg = cellConfigs[cellId] || {
            symbol: DEFAULT_SYMBOLS[cellId % DEFAULT_SYMBOLS.length],
            timeframe: '1D',
            smaEnabled: false,
          };
          return (
            <ChartCell
              key={`${layoutId}-${cellId}`}
              cellId={cellId}
              symbol={cfg.symbol}
              timeframe={cfg.timeframe}
              showSMA={cfg.smaEnabled}
              isFullscreen={fullscreenCell === cellId}
              onFullscreenToggle={handleFullscreenToggle}
              onCrosshairMove={handleCrosshairMove}
              syncTime={syncEnabled && syncSource !== cellId ? syncTime : null}
              onConfigChange={handleConfigChange}
            />
          );
        })}
      </div>

      {/* ── Bottom status bar ──────────────────────────────────── */}
      <div className={s.statusBar}>
        <span className={s.statusText}>
          {layout.label} layout
        </span>
        <span className={s.statusText}>
          {cellCount} {cellCount === 1 ? 'chart' : 'charts'}
        </span>
        {syncEnabled && (
          <span className={s.statusSync}>
            crosshair sync
          </span>
        )}
        {isFs && (
          <span className={s.statusFullscreen}>
            fullscreen: {cellConfigs[fullscreenCell]?.symbol || ''}
          </span>
        )}
        <div className={s.spacer} />
        <span className={s.statusBrand}>
          Aura Alpha
        </span>
      </div>
    </div>
  );
}
