/* ═══════════════════════════════════════════════════════════════════════════
   ChartCell — Individual chart cell for multi-chart workspace
   Wraps TradingView Lightweight Charts v5 createChart()
   Handles resize, OHLCV fetch, candlestick + volume + SMA overlays
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useRef, useCallback, memo } from 'react';
import * as LWC from 'lightweight-charts';
const { createChart, CandlestickSeries, HistogramSeries, LineSeries, AreaSeries, ColorType, CrosshairMode } = LWC;
import { api } from '../utils/api';

/* ── Design tokens ─────────────────────────────────────────────── */
const C = {
  bg:          '#0D1117',
  surface:     '#161B22',
  surface2:    '#1C2128',
  border:      '#30363D',
  text:        '#E6EDF3',
  muted:       '#8B949E',
  green:       '#3FB950',
  red:         '#F85149',
  blue:        '#58A6FF',
  amber:       '#D29922',
  purple:      '#BC8CFF',
  grid:        '#1C2128',
  crosshair:   '#58A6FF',
  volumeUp:    'rgba(63,185,80,0.3)',
  volumeDown:  'rgba(248,81,73,0.3)',
};

const mono = "'JetBrains Mono', monospace";

const TIMEFRAMES = ['1D', '1W', '1M', '3M', '6M', '1Y', 'ALL'];

const SMA_CONFIG = [
  { period: 20,  color: C.blue, label: 'SMA 20' },
  { period: 50,  color: C.amber, label: 'SMA 50' },
  { period: 200, color: C.purple, label: 'SMA 200' },
];

/* ── Helpers ───────────────────────────────────────────────────── */
function parseBarTime(bar, index) {
  const raw = bar.timestamp || bar.date || bar.time;
  if (raw != null) {
    if (typeof raw === 'number') return raw;
    const d = new Date(raw);
    if (!isNaN(d.getTime())) return Math.floor(d.getTime() / 1000);
  }
  return 1609459200 + index * 86400;
}

function computeSMA(bars, period) {
  const result = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < period - 1) continue;
    let sum = 0;
    for (let j = i - period + 1; j <= i; j++) sum += bars[j].close;
    result.push({ time: bars[i].time, value: sum / period });
  }
  return result;
}

/* ── EMA calculation ──────────────────────────────────────────── */
function calcEMA(data, period) {
  if (data.length === 0) return [];
  const k = 2 / (period + 1);
  const result = [data[0]];
  for (let i = 1; i < data.length; i++) {
    result.push(result[i - 1] + k * (data[i] - result[i - 1]));
  }
  return result;
}

/* ── RSI (Relative Strength Index) ────────────────────────────── */
function calcRSI(closes, period = 14) {
  if (closes.length < period + 1) return [];
  const deltas = [];
  for (let i = 1; i < closes.length; i++) {
    deltas.push(closes[i] - closes[i - 1]);
  }

  let avgGain = 0;
  let avgLoss = 0;
  for (let i = 0; i < period; i++) {
    if (deltas[i] > 0) avgGain += deltas[i];
    else avgLoss += Math.abs(deltas[i]);
  }
  avgGain /= period;
  avgLoss /= period;

  const rsi = [];
  // First RSI value at index = period (in the closes array)
  const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
  rsi.push({ index: period, value: avgLoss === 0 ? 100 : 100 - 100 / (1 + rs) });

  for (let i = period; i < deltas.length; i++) {
    const gain = deltas[i] > 0 ? deltas[i] : 0;
    const loss = deltas[i] < 0 ? Math.abs(deltas[i]) : 0;
    avgGain = (avgGain * (period - 1) + gain) / period;
    avgLoss = (avgLoss * (period - 1) + loss) / period;
    const rs2 = avgLoss === 0 ? 100 : avgGain / avgLoss;
    rsi.push({ index: i + 1, value: avgLoss === 0 ? 100 : 100 - 100 / (1 + rs2) });
  }
  return rsi;
}

/* ── Bollinger Bands ──────────────────────────────────────────── */
function calcBollingerBands(closes, period = 20, stdDevMultiplier = 2) {
  const result = [];
  for (let i = period - 1; i < closes.length; i++) {
    let sum = 0;
    for (let j = i - period + 1; j <= i; j++) sum += closes[j];
    const mean = sum / period;

    let sqSum = 0;
    for (let j = i - period + 1; j <= i; j++) sqSum += (closes[j] - mean) ** 2;
    const stddev = Math.sqrt(sqSum / period);

    result.push({
      index: i,
      middle: mean,
      upper: mean + stdDevMultiplier * stddev,
      lower: mean - stdDevMultiplier * stddev,
    });
  }
  return result;
}

/* ── MACD ─────────────────────────────────────────────────────── */
function calcMACD(closes, fastPeriod = 12, slowPeriod = 26, signalPeriod = 9) {
  if (closes.length < slowPeriod) return { macd: [], signal: [], histogram: [] };
  const fastEMA = calcEMA(closes, fastPeriod);
  const slowEMA = calcEMA(closes, slowPeriod);
  const macdLine = [];
  for (let i = 0; i < closes.length; i++) {
    macdLine.push(fastEMA[i] - slowEMA[i]);
  }
  const signalLine = calcEMA(macdLine, signalPeriod);
  return {
    macd: macdLine,
    signal: signalLine,
    histogram: macdLine.map((v, i) => v - signalLine[i]),
  };
}

/* ── Popular symbol suggestions for autocomplete ───────────────── */
const POPULAR_SYMBOLS = [
  'AAPL', 'MSFT', 'GOOGL', 'AMZN', 'NVDA', 'TSLA', 'META', 'AMD',
  'SPY', 'QQQ', 'IWM', 'DIA', 'NFLX', 'AVGO', 'CRM', 'ORCL',
  'JPM', 'BAC', 'GS', 'V', 'MA', 'PYPL', 'SQ', 'COIN',
  'XOM', 'CVX', 'COST', 'WMT', 'HD', 'LOW', 'NKE', 'DIS',
  'BA', 'CAT', 'GE', 'UNH', 'PFE', 'JNJ', 'ABBV', 'LLY',
  'BTC', 'ETH', 'SOL', 'DOGE', 'ADA', 'AVAX', 'DOT', 'LINK',
];

/* ═══════════════════════════════════════════════════════════════════════════
   ChartCell Component
   ═══════════════════════════════════════════════════════════════════════════ */
function ChartCell({
  cellId,
  symbol: initialSymbol = 'SPY',
  timeframe: initialTimeframe = '1D',
  showSMA = false,
  isFullscreen = false,
  onFullscreenToggle,
  onCrosshairMove,
  syncTime,
  onConfigChange,
}) {
  const containerRef = useRef(null);
  const chartRef = useRef(null);
  const candleRef = useRef(null);
  const volumeRef = useRef(null);
  const smaSeriesRef = useRef({});
  const crosshairSubRef = useRef(null);
  const rsiSeriesRef = useRef({});      // { line, overbought, oversold }
  const bbSeriesRef = useRef({});       // { middle, upper, lower, fill }
  const macdSeriesRef = useRef({});     // { macd, signal, histogram }

  const [symbol, setSymbol] = useState(initialSymbol);
  const [inputValue, setInputValue] = useState(initialSymbol);
  const [timeframe, setTimeframe] = useState(initialTimeframe);
  const [bars, setBars] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [smaEnabled, setSmaEnabled] = useState(showSMA);
  const [showRSI, setShowRSI] = useState(false);
  const [showBB, setShowBB] = useState(false);
  const [showMACD, setShowMACD] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [filteredSuggestions, setFilteredSuggestions] = useState([]);
  const [signals, setSignals] = useState([]);
  const [showSignals, setShowSignals] = useState(true);
  const inputRef = useRef(null);
  const suggestionsRef = useRef(null);

  /* ── Fetch OHLCV ─────────────────────────────────────────────── */
  const fetchData = useCallback(async (sym, tf) => {
    if (!sym) return;
    setLoading(true);
    setError(null);
    try {
      const encoded = encodeURIComponent(sym);
      const data = await api(`/charts/ohlcv/${encoded}?timeframe=${encodeURIComponent(tf)}&bars=500`);
      if (data) {
        const rawBars = data.bars || data.data || [];
        const processed = rawBars.map((bar, i) => ({
          time: parseBarTime(bar, i),
          open: Number(bar.open),
          high: Number(bar.high),
          low: Number(bar.low),
          close: Number(bar.close),
          volume: Number(bar.volume) || 0,
        }));
        processed.sort((a, b) => a.time - b.time);
        // Deduplicate by time
        const seen = new Set();
        const deduped = [];
        for (const bar of processed) {
          if (!seen.has(bar.time)) {
            seen.add(bar.time);
            deduped.push(bar);
          }
        }
        setBars(deduped);
      } else {
        setError('No data');
        setBars([]);
      }
    } catch (e) {
      setError(e.message || 'Fetch failed');
      setBars([]);
    }
    setLoading(false);
  }, []);

  /* ── Fetch signals for current symbol ─────────────────────────── */
  const fetchSignals = useCallback(async (sym) => {
    try {
      const allSignals = [];
      const [signalsRes, liveRes] = await Promise.allSettled([
        api(`/signals?symbol=${encodeURIComponent(sym)}&days=30`, { silent: true }),
        api(`/scanners/signals/live`, { silent: true }),
      ]);
      if (signalsRes.status === 'fulfilled' && signalsRes.value) {
        const sigs = signalsRes.value?.signals || signalsRes.value?.results || signalsRes.value || [];
        if (Array.isArray(sigs)) allSignals.push(...sigs);
      }
      if (liveRes.status === 'fulfilled' && liveRes.value) {
        const live = liveRes.value?.signals || liveRes.value?.results || liveRes.value || [];
        if (Array.isArray(live)) {
          allSignals.push(...live.filter(s => (s.symbol || s.ticker || '').toUpperCase() === sym.toUpperCase()));
        }
      }
      setSignals(allSignals);
    } catch { setSignals([]); }
  }, []);

  /* ── Initial fetch ───────────────────────────────────────────── */
  useEffect(() => {
    fetchData(symbol, timeframe);
    fetchSignals(symbol);
  }, []);   // eslint-disable-line react-hooks/exhaustive-deps

  /* ── Notify parent of config changes (for localStorage persist) */
  useEffect(() => {
    if (onConfigChange) {
      onConfigChange(cellId, { symbol, timeframe, smaEnabled, showRSI, showBB, showMACD });
    }
  }, [symbol, timeframe, smaEnabled, showRSI, showBB, showMACD, showSignals]);   // eslint-disable-line react-hooks/exhaustive-deps

  /* ── Symbol autocomplete ─────────────────────────────────────── */
  const handleInputChange = (e) => {
    const val = e.target.value.toUpperCase();
    setInputValue(val);
    if (val.length > 0) {
      const filtered = POPULAR_SYMBOLS.filter(s =>
        s.startsWith(val) && s !== val
      ).slice(0, 6);
      setFilteredSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  };

  const selectSuggestion = (sym) => {
    setInputValue(sym);
    setSymbol(sym);
    setShowSuggestions(false);
    fetchData(sym, timeframe);
    fetchSignals(sym);
  };

  const handleSymbolSubmit = (e) => {
    e.preventDefault();
    const sym = inputValue.trim().toUpperCase();
    if (sym && sym !== symbol) {
      setSymbol(sym);
      fetchData(sym, timeframe);
      fetchSignals(sym);
    }
    setShowSuggestions(false);
  };

  const handleTimeframeChange = (tf) => {
    setTimeframe(tf);
    fetchData(symbol, tf);
  };

  /* ── Close suggestions on outside click ──────────────────────── */
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (
        suggestionsRef.current && !suggestionsRef.current.contains(e.target) &&
        inputRef.current && !inputRef.current.contains(e.target)
      ) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  /* ── Create / destroy chart ──────────────────────────────────── */
  useEffect(() => {
    if (!containerRef.current) return;

    const chart = createChart(containerRef.current, {
      width: containerRef.current.clientWidth,
      height: containerRef.current.clientHeight,
      layout: {
        background: { type: ColorType.Solid, color: C.bg },
        textColor: C.text,
        fontFamily: mono,
        fontSize: 10,
      },
      grid: {
        vertLines: { color: C.grid },
        horzLines: { color: C.grid },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { color: C.crosshair, width: 1, style: 2, labelBackgroundColor: C.surface },
        horzLine: { color: C.crosshair, width: 1, style: 2, labelBackgroundColor: C.surface },
      },
      rightPriceScale: {
        borderColor: C.border,
        scaleMargins: { top: 0.08, bottom: 0.22 },
      },
      timeScale: {
        borderColor: C.border,
        timeVisible: true,
        secondsVisible: false,
      },
      handleScroll: { vertTouchDrag: false },
      watermark: { visible: false },
    });

    const candleSeries = chart.addSeries(CandlestickSeries, {
      upColor: C.green,
      downColor: C.red,
      borderDownColor: C.red,
      borderUpColor: C.green,
      wickDownColor: C.red,
      wickUpColor: C.green,
    });

    const volumeSeries = chart.addSeries(HistogramSeries, {
      priceFormat: { type: 'volume' },
      priceScaleId: 'volume',
    });

    chart.priceScale('volume').applyOptions({
      scaleMargins: { top: 0.8, bottom: 0 },
    });

    chartRef.current = chart;
    candleRef.current = candleSeries;
    volumeRef.current = volumeSeries;

    /* Crosshair sync — emit moves */
    crosshairSubRef.current = chart.subscribeCrosshairMove((param) => {
      if (onCrosshairMove && param.time) {
        onCrosshairMove(cellId, param.time);
      }
    });

    /* Resize observer */
    const ro = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width > 0 && height > 0) {
          chart.applyOptions({ width, height });
        }
      }
    });
    ro.observe(containerRef.current);

    return () => {
      ro.disconnect();
      crosshairSubRef.current = null;
      chart.remove();
      chartRef.current = null;
      candleRef.current = null;
      volumeRef.current = null;
      smaSeriesRef.current = {};
      rsiSeriesRef.current = {};
      bbSeriesRef.current = {};
      macdSeriesRef.current = {};
    };
  }, [cellId, onCrosshairMove]);   // eslint-disable-line react-hooks/exhaustive-deps

  /* ── Update candle + volume data ─────────────────────────────── */
  useEffect(() => {
    if (!candleRef.current || bars.length === 0) return;

    const candleData = bars.map(({ time, open, high, low, close }) => ({ time, open, high, low, close }));
    const volumeData = bars.map((bar) => ({
      time: bar.time,
      value: bar.volume,
      color: bar.close >= bar.open ? C.volumeUp : C.volumeDown,
    }));

    candleRef.current.setData(candleData);
    volumeRef.current.setData(volumeData);
    chartRef.current?.timeScale().fitContent();
  }, [bars]);

  /* ── Signal markers on candle series ─────────────────────────── */
  useEffect(() => {
    if (!candleRef.current || !showSignals || !signals || signals.length === 0) {
      if (candleRef.current) {
        try { candleRef.current.setMarkers([]); } catch { /* ignore */ }
      }
      return;
    }
    const barTimeSet = new Set(bars.map(b => b.time));
    const markers = [];
    for (const sig of signals) {
      const rawTime = sig.timestamp || sig.date || sig.signal_time;
      if (!rawTime) continue;
      let t = typeof rawTime === 'number' ? rawTime : Math.floor(new Date(rawTime).getTime() / 1000);
      // Snap to nearest day boundary for daily bars
      const dayT = t - (t % 86400);
      if (barTimeSet.has(dayT)) t = dayT;
      else if (!barTimeSet.has(t)) continue; // skip if no matching bar

      const dir = (sig.direction || sig.signal_type || '').toLowerCase();
      const isBuy = dir.includes('buy') || dir.includes('long');
      markers.push({
        time: t,
        position: isBuy ? 'belowBar' : 'aboveBar',
        color: isBuy ? C.green : C.red,
        shape: isBuy ? 'arrowUp' : 'arrowDown',
        text: (sig.strategy || (isBuy ? 'BUY' : 'SELL')).slice(0, 12),
      });
    }
    markers.sort((a, b) => a.time - b.time);
    try { candleRef.current.setMarkers(markers); } catch { /* ignore */ }
  }, [bars, signals, showSignals]);

  /* ── SMA overlays ────────────────────────────────────────────── */
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart || bars.length === 0) return;

    if (smaEnabled) {
      for (const cfg of SMA_CONFIG) {
        if (bars.length < cfg.period) continue;
        const data = computeSMA(bars, cfg.period);
        if (!smaSeriesRef.current[cfg.period]) {
          const series = chart.addSeries(LineSeries, {
            color: cfg.color,
            lineWidth: 1,
            priceLineVisible: false,
            lastValueVisible: false,
            crosshairMarkerVisible: false,
          });
          series.setData(data);
          smaSeriesRef.current[cfg.period] = series;
        } else {
          smaSeriesRef.current[cfg.period].setData(data);
        }
      }
    } else {
      // Remove SMA series
      for (const [period, series] of Object.entries(smaSeriesRef.current)) {
        try { chart.removeSeries(series); } catch (_) { /* already removed */ }
      }
      smaSeriesRef.current = {};
    }
  }, [bars, smaEnabled]);

  /* ── RSI overlay ──────────────────────────────────────────────── */
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart || bars.length === 0) return;

    if (showRSI) {
      const closes = bars.map(b => b.close);
      const rsiData = calcRSI(closes, 14);
      if (rsiData.length === 0) return;

      // Build segmented RSI line data with colors
      const rsiLineData = rsiData.map(pt => ({
        time: bars[pt.index].time,
        value: pt.value,
        color: pt.value > 70 ? C.red : pt.value < 30 ? C.green : C.blue,
      }));

      // Overbought line at 70
      const obData = rsiData.map(pt => ({ time: bars[pt.index].time, value: 70 }));
      // Oversold line at 30
      const osData = rsiData.map(pt => ({ time: bars[pt.index].time, value: 30 }));

      if (!rsiSeriesRef.current.line) {
        const rsiLine = chart.addSeries(LineSeries, {
          color: C.blue,
          lineWidth: 1.5,
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
          priceScaleId: 'rsi',
          pointMarkersVisible: false,
        });
        chart.priceScale('rsi').applyOptions({
          scaleMargins: { top: 0.82, bottom: 0.02 },
          borderVisible: false,
          drawTicks: false,
        });

        const obLine = chart.addSeries(LineSeries, {
          color: C.red,
          lineWidth: 1,
          lineStyle: 2, // dashed
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
          priceScaleId: 'rsi',
        });

        const osLine = chart.addSeries(LineSeries, {
          color: C.green,
          lineWidth: 1,
          lineStyle: 2, // dashed
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
          priceScaleId: 'rsi',
        });

        rsiLine.setData(rsiLineData);
        obLine.setData(obData);
        osLine.setData(osData);
        rsiSeriesRef.current = { line: rsiLine, overbought: obLine, oversold: osLine };
      } else {
        rsiSeriesRef.current.line.setData(rsiLineData);
        rsiSeriesRef.current.overbought.setData(obData);
        rsiSeriesRef.current.oversold.setData(osData);
      }
    } else {
      // Remove RSI series
      for (const series of Object.values(rsiSeriesRef.current)) {
        try { chart.removeSeries(series); } catch (_) { /* already removed */ }
      }
      rsiSeriesRef.current = {};
    }
  }, [bars, showRSI]);

  /* ── Bollinger Bands overlay ──────────────────────────────────── */
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart || bars.length === 0) return;

    if (showBB) {
      const closes = bars.map(b => b.close);
      const bbData = calcBollingerBands(closes, 20, 2);
      if (bbData.length === 0) return;

      const middleData = bbData.map(pt => ({ time: bars[pt.index].time, value: pt.middle }));
      const upperData = bbData.map(pt => ({ time: bars[pt.index].time, value: pt.upper }));
      const lowerData = bbData.map(pt => ({ time: bars[pt.index].time, value: pt.lower }));

      if (!bbSeriesRef.current.middle) {
        // Fill area: upper band as line, lower as baseline
        const fillSeries = chart.addSeries(AreaSeries, {
          lineColor: 'transparent',
          topColor: 'rgba(210,153,34,0.10)',
          bottomColor: 'rgba(210,153,34,0.02)',
          lineWidth: 0,
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
        });
        // Use upper band as area data
        fillSeries.setData(bbData.map(pt => ({
          time: bars[pt.index].time,
          value: pt.upper,
        })));

        const middleLine = chart.addSeries(LineSeries, {
          color: C.amber,
          lineWidth: 1.5,
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
        });

        const upperLine = chart.addSeries(LineSeries, {
          color: 'rgba(210,153,34,0.5)',
          lineWidth: 1,
          lineStyle: 2, // dashed
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
        });

        const lowerLine = chart.addSeries(LineSeries, {
          color: 'rgba(210,153,34,0.5)',
          lineWidth: 1,
          lineStyle: 2, // dashed
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
        });

        middleLine.setData(middleData);
        upperLine.setData(upperData);
        lowerLine.setData(lowerData);
        bbSeriesRef.current = { middle: middleLine, upper: upperLine, lower: lowerLine, fill: fillSeries };
      } else {
        bbSeriesRef.current.fill.setData(bbData.map(pt => ({
          time: bars[pt.index].time,
          value: pt.upper,
        })));
        bbSeriesRef.current.middle.setData(middleData);
        bbSeriesRef.current.upper.setData(upperData);
        bbSeriesRef.current.lower.setData(lowerData);
      }
    } else {
      // Remove BB series
      for (const series of Object.values(bbSeriesRef.current)) {
        try { chart.removeSeries(series); } catch (_) { /* already removed */ }
      }
      bbSeriesRef.current = {};
    }
  }, [bars, showBB]);

  /* ── MACD overlay ─────────────────────────────────────────────── */
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart || bars.length === 0) return;

    if (showMACD) {
      const closes = bars.map(b => b.close);
      const { macd, signal, histogram } = calcMACD(closes, 12, 26, 9);
      if (macd.length === 0) return;

      // Start from index 26 (slowPeriod) for meaningful data
      const startIdx = 25;
      const macdData = [];
      const signalData = [];
      const histData = [];

      for (let i = startIdx; i < bars.length; i++) {
        macdData.push({ time: bars[i].time, value: macd[i] });
        signalData.push({ time: bars[i].time, value: signal[i] });
        histData.push({
          time: bars[i].time,
          value: histogram[i],
          color: histogram[i] >= 0 ? C.green : C.red,
        });
      }

      if (!macdSeriesRef.current.macd) {
        const histSeries = chart.addSeries(HistogramSeries, {
          priceScaleId: 'macd',
          priceLineVisible: false,
          lastValueVisible: false,
          priceFormat: { type: 'price', precision: 4, minMove: 0.0001 },
        });
        chart.priceScale('macd').applyOptions({
          scaleMargins: { top: 0.88, bottom: 0.0 },
          borderVisible: false,
          drawTicks: false,
        });

        const macdLine = chart.addSeries(LineSeries, {
          color: C.blue,
          lineWidth: 1.5,
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
          priceScaleId: 'macd',
        });

        const signalLine = chart.addSeries(LineSeries, {
          color: C.amber,
          lineWidth: 1.5,
          priceLineVisible: false,
          lastValueVisible: false,
          crosshairMarkerVisible: false,
          priceScaleId: 'macd',
        });

        histSeries.setData(histData);
        macdLine.setData(macdData);
        signalLine.setData(signalData);
        macdSeriesRef.current = { macd: macdLine, signal: signalLine, histogram: histSeries };
      } else {
        macdSeriesRef.current.histogram.setData(histData);
        macdSeriesRef.current.macd.setData(macdData);
        macdSeriesRef.current.signal.setData(signalData);
      }
    } else {
      // Remove MACD series
      for (const series of Object.values(macdSeriesRef.current)) {
        try { chart.removeSeries(series); } catch (_) { /* already removed */ }
      }
      macdSeriesRef.current = {};
    }
  }, [bars, showMACD]);

  /* ── Adjust main chart margins for sub-panes ──────────────────── */
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart) return;
    // Shrink main chart top area to make room for RSI/MACD below
    let bottom = 0.22; // default for volume
    if (showRSI) bottom += 0.12;
    if (showMACD) bottom += 0.08;
    try {
      chart.priceScale('right').applyOptions({
        scaleMargins: { top: 0.08, bottom },
      });
      // Reposition volume above the sub-panes
      const volTop = 1.0 - (bottom - 0.02);
      chart.priceScale('volume').applyOptions({
        scaleMargins: { top: Math.max(0.65, volTop), bottom: 0 },
      });
    } catch (_) { /* chart may not be ready */ }

    // Adjust RSI position if MACD is also visible
    if (showRSI && rsiSeriesRef.current.line) {
      const rsiTop = showMACD ? 0.76 : 0.80;
      try {
        chart.priceScale('rsi').applyOptions({
          scaleMargins: { top: rsiTop, bottom: showMACD ? 0.14 : 0.02 },
        });
      } catch (_) { /* ignore */ }
    }
  }, [showRSI, showMACD]);

  /* ── Crosshair sync — receive from other panes ───────────────── */
  useEffect(() => {
    if (!chartRef.current || syncTime == null) return;
    try {
      chartRef.current.setCrosshairPosition(undefined, undefined, syncTime);
    } catch (_) { /* ignore if time not in data range */ }
  }, [syncTime]);

  /* ── Last bar stats ──────────────────────────────────────────── */
  const lastBar = bars.length > 0 ? bars[bars.length - 1] : null;
  const prevBar = bars.length > 1 ? bars[bars.length - 2] : null;
  const priceChange = lastBar && prevBar ? lastBar.close - prevBar.close : 0;
  const pctChange = prevBar && prevBar.close !== 0 ? (priceChange / prevBar.close) * 100 : 0;
  const isUp = priceChange >= 0;

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      background: C.bg,
      border: `1px solid ${C.border}`,
      borderRadius: '6px',
      overflow: 'hidden',
      minHeight: 0,
      height: '100%',
      position: 'relative',
    }}>
      {/* ── Cell toolbar ─────────────────────────────────────────── */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        gap: '4px',
        padding: '4px 8px',
        background: C.surface,
        borderBottom: `1px solid ${C.border}`,
        flexShrink: 0,
        flexWrap: 'wrap',
        minHeight: '34px',
      }}>
        {/* Symbol input with autocomplete */}
        <div style={{ position: 'relative' }}>
          <form onSubmit={handleSymbolSubmit} style={{ display: 'flex', alignItems: 'center' }}>
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={handleInputChange}
              onFocus={() => {
                if (inputValue.length > 0) {
                  const filtered = POPULAR_SYMBOLS.filter(s =>
                    s.startsWith(inputValue) && s !== inputValue
                  ).slice(0, 6);
                  if (filtered.length > 0) setShowSuggestions(true);
                }
              }}
              style={{
                background: C.surface2,
                border: `1px solid ${C.border}`,
                borderRadius: '6px',
                padding: '3px 8px',
                color: C.text,
                fontFamily: mono,
                fontSize: '12px',
                fontWeight: 700,
                width: '72px',
                outline: 'none',
              }}
              placeholder="SYM"
            />
          </form>

          {/* Autocomplete dropdown */}
          {showSuggestions && filteredSuggestions.length > 0 && (
            <div
              ref={suggestionsRef}
              style={{
                position: 'absolute',
                top: '100%',
                left: 0,
                zIndex: 100,
                background: C.surface,
                border: `1px solid ${C.border}`,
                borderRadius: '6px',
                marginTop: '2px',
                minWidth: '72px',
                boxShadow: '0 4px 12px rgba(0,0,0,0.5)',
                overflow: 'hidden',
              }}
            >
              {filteredSuggestions.map((s) => (
                <div
                  key={s}
                  onClick={() => selectSuggestion(s)}
                  style={{
                    padding: '5px 10px',
                    fontFamily: mono,
                    fontSize: '11px',
                    fontWeight: 600,
                    color: C.text,
                    cursor: 'pointer',
                    borderBottom: `1px solid ${C.border}`,
                  }}
                  onMouseEnter={(e) => { e.target.style.background = C.surface2; }}
                  onMouseLeave={(e) => { e.target.style.background = 'transparent'; }}
                >
                  {s}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Price info */}
        {lastBar && (
          <span style={{
            fontFamily: mono,
            fontSize: '11px',
            fontWeight: 700,
            color: isUp ? C.green : C.red,
            marginLeft: '2px',
          }}>
            ${lastBar.close.toFixed(2)}
            <span style={{ fontSize: '10px', fontWeight: 500, marginLeft: '4px', opacity: 0.8 }}>
              {isUp ? '+' : ''}{pctChange.toFixed(2)}%
            </span>
          </span>
        )}

        <div style={{ flex: 1 }} />

        {/* Timeframe buttons */}
        {TIMEFRAMES.map((tf) => (
          <button
            key={tf}
            onClick={() => handleTimeframeChange(tf)}
            style={{
              background: timeframe === tf ? C.blue : 'transparent',
              color: timeframe === tf ? '#fff' : C.muted,
              border: 'none',
              borderRadius: '6px',
              padding: '2px 5px',
              fontFamily: mono,
              fontSize: '9px',
              fontWeight: 600,
              cursor: 'pointer',
              lineHeight: '16px',
              transition: 'all 0.15s ease',
            }}
          >
            {tf}
          </button>
        ))}

        {/* SMA toggle */}
        <button
          onClick={() => setSmaEnabled(v => !v)}
          title="Toggle SMA 20/50/200"
          style={{
            background: smaEnabled ? C.blue : 'transparent',
            color: smaEnabled ? '#fff' : C.muted,
            border: `1px solid ${smaEnabled ? C.blue : C.border}`,
            borderRadius: '6px',
            padding: '2px 5px',
            fontFamily: mono,
            fontSize: '9px',
            fontWeight: 600,
            cursor: 'pointer',
            lineHeight: '16px',
          }}
        >
          SMA
        </button>

        {/* RSI toggle */}
        <button
          onClick={() => setShowRSI(v => !v)}
          title="Toggle RSI (14)"
          style={{
            background: showRSI ? C.blue : 'transparent',
            color: showRSI ? '#fff' : C.muted,
            border: `1px solid ${showRSI ? C.blue : C.border}`,
            borderRadius: '6px',
            padding: '2px 5px',
            fontFamily: mono,
            fontSize: '9px',
            fontWeight: 600,
            cursor: 'pointer',
            lineHeight: '16px',
          }}
        >
          RSI
        </button>

        {/* Bollinger Bands toggle */}
        <button
          onClick={() => setShowBB(v => !v)}
          title="Toggle Bollinger Bands (20, 2)"
          style={{
            background: showBB ? C.amber : 'transparent',
            color: showBB ? '#fff' : C.muted,
            border: `1px solid ${showBB ? C.amber : C.border}`,
            borderRadius: '6px',
            padding: '2px 5px',
            fontFamily: mono,
            fontSize: '9px',
            fontWeight: 600,
            cursor: 'pointer',
            lineHeight: '16px',
          }}
        >
          BB
        </button>

        {/* MACD toggle */}
        <button
          onClick={() => setShowMACD(v => !v)}
          title="Toggle MACD (12, 26, 9)"
          style={{
            background: showMACD ? C.blue : 'transparent',
            color: showMACD ? '#fff' : C.muted,
            border: `1px solid ${showMACD ? C.blue : C.border}`,
            borderRadius: '6px',
            padding: '2px 5px',
            fontFamily: mono,
            fontSize: '9px',
            fontWeight: 600,
            cursor: 'pointer',
            lineHeight: '16px',
          }}
        >
          MACD
        </button>

        {/* Signal toggle */}
        <button
          onClick={() => setShowSignals(v => !v)}
          title={`${showSignals ? 'Hide' : 'Show'} signals${signals.length > 0 ? ` (${signals.length})` : ''}`}
          style={{
            background: showSignals && signals.length > 0 ? C.green : 'transparent',
            color: showSignals && signals.length > 0 ? '#fff' : C.muted,
            border: `1px solid ${showSignals && signals.length > 0 ? C.green : C.border}`,
            borderRadius: '6px',
            padding: '2px 5px',
            fontFamily: mono,
            fontSize: '9px',
            fontWeight: 600,
            cursor: 'pointer',
            lineHeight: '16px',
            display: 'flex',
            alignItems: 'center',
            gap: '2px',
          }}
        >
          <svg width="8" height="8" viewBox="0 0 10 10">
            <polygon points="5,0 10,10 0,10" fill="currentColor" />
          </svg>
          {signals.length > 0 ? signals.length : ''}
        </button>

        {/* Fullscreen toggle */}
        <button
          onClick={() => onFullscreenToggle && onFullscreenToggle(cellId)}
          title={isFullscreen ? 'Exit fullscreen' : 'Fullscreen'}
          style={{
            background: 'transparent',
            color: C.muted,
            border: `1px solid ${C.border}`,
            borderRadius: '6px',
            padding: '2px 4px',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {isFullscreen ? (
            <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M6 2H2v4M14 10v4h-4M10 14h4v-4M2 6V2h4" />
            </svg>
          ) : (
            <svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M2 6V2h4M14 10v4h-4M10 2h4v4M2 10v4h4" />
            </svg>
          )}
        </button>
      </div>

      {/* ── Chart area ───────────────────────────────────────────── */}
      <div style={{ flex: 1, position: 'relative', minHeight: 0 }}>
        {loading && (
          <div style={{
            position: 'absolute', inset: 0, display: 'flex',
            flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            zIndex: 5, background: 'rgba(13,17,23,0.85)',
          }}>
            <div style={{
              width: '24px', height: '24px',
              border: `2px solid ${C.border}`,
              borderTop: `2px solid ${C.blue}`,
              borderRadius: '50%',
              animation: 'cc-spin 0.8s linear infinite',
            }} />
            <style>{`@keyframes cc-spin { to { transform: rotate(360deg); } }`}</style>
          </div>
        )}

        {!loading && error && (
          <div style={{
            position: 'absolute', inset: 0, display: 'flex',
            alignItems: 'center', justifyContent: 'center',
            color: C.red, fontSize: '12px', fontFamily: mono,
            textAlign: 'center', padding: '12px',
          }}>
            {error}
          </div>
        )}

        {!loading && !error && bars.length === 0 && (
          <div style={{
            position: 'absolute', inset: 0, display: 'flex',
            flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            color: C.muted, gap: '8px',
          }}>
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke={C.muted} strokeWidth="1.5">
              <rect x="3" y="3" width="18" height="18" rx="2" />
              <path d="M3 9h18M9 3v18" />
            </svg>
            <span style={{ fontSize: '12px', fontFamily: mono }}>Enter a symbol</span>
          </div>
        )}

        <div ref={containerRef} style={{ width: '100%', height: '100%' }} />
      </div>

      {/* Indicator legends */}
      {(smaEnabled || showRSI || showBB || showMACD) && bars.length > 0 && (
        <div style={{
          display: 'flex',
          gap: '10px',
          padding: '3px 8px',
          background: C.surface,
          borderTop: `1px solid ${C.border}`,
          flexShrink: 0,
          flexWrap: 'wrap',
        }}>
          {/* SMA legend */}
          {smaEnabled && SMA_CONFIG.map((cfg) => (
            <span key={cfg.period} style={{
              fontFamily: mono,
              fontSize: '9px',
              color: cfg.color,
              fontWeight: 600,
              opacity: bars.length >= cfg.period ? 1 : 0.3,
            }}>
              {cfg.label}
            </span>
          ))}

          {/* RSI legend */}
          {showRSI && (
            <span style={{ fontFamily: mono, fontSize: '9px', color: C.blue, fontWeight: 600 }}>
              RSI(14)
            </span>
          )}

          {/* BB legend */}
          {showBB && (
            <span style={{ fontFamily: mono, fontSize: '9px', color: C.amber, fontWeight: 600 }}>
              BB(20,2)
            </span>
          )}

          {/* MACD legend */}
          {showMACD && (
            <>
              <span style={{ fontFamily: mono, fontSize: '9px', color: C.blue, fontWeight: 600 }}>
                MACD
              </span>
              <span style={{ fontFamily: mono, fontSize: '9px', color: C.amber, fontWeight: 600 }}>
                Signal
              </span>
            </>
          )}
        </div>
      )}
    </div>
  );
}

export default memo(ChartCell);
